using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter;

    public StringFormatterTests()
    {
        _formatter = new StringFormatter();
    }

    // ── FormatPhoneNumber ───────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesExpectedPattern()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123", DisplayName = "Too short")]
    [DataRow("12345678901", DisplayName = "Too long")]
    [DataRow("", DisplayName = "Empty")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ───────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ReturnsGreetingWithMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_StartsWithDearAndTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith("Dear Dr.", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.Contains("Johnson", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhitespaceName_ThrowsArgumentException(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ────────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlySlugChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_StartsWithFirstWord()
    {
        var result = _formatter.GenerateSlug("Getting Started with MSTest");

        Assert.StartsWith("getting", result);
    }

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_EndsWithLastWord()
    {
        var result = _formatter.GenerateSlug("Getting Started with MSTest");

        Assert.EndsWith("mstest", result);
    }

    [TestMethod]
    [DataRow("  Padded Title  ", "padded-title", DisplayName = "Trims whitespace")]
    [DataRow("UPPER CASE", "upper-case", DisplayName = "Lowercases")]
    [DataRow("dots...and---dashes", "dots-and-dashes", DisplayName = "Collapses separators")]
    public void GenerateSlug_VariousInputs_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhitespace_ThrowsArgumentException(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ──────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(42m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_WithCents_ReturnsExactValue()
    {
        var result = _formatter.FormatCurrency(9.50m);

        Assert.AreEqual("$9.50", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.00m);

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatCurrency_Zero_ReturnsZeroFormatted()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }

    [TestMethod]
    public void FormatCurrency_LargeAmount_MatchesDecimalPattern()
    {
        var result = _formatter.FormatCurrency(1234567.89m, "£");

        Assert.MatchesRegex(@"^£\d+\.\d{2}$", result);
    }
}

